class Solution:
    def smallestSubarrays(self, nums):
        n = len(nums)
        ans = [0] * n
        for i in range(n):
            total = 0
            for j in range(i, n):
                total |= nums[j]
            cur = 0
            j = i
            while j < n and cur != total:
                cur |= nums[j]
                j += 1
            ans[i] = max(1, j - i)
        return ans

