class Solution:
    def smallestSubarrays(self, nums):
        n = len(nums)
        last = [-1] * 30
        ans = [0] * n
        for i in range(n - 1, -1, -1):
            for b in range(30):
                if nums[i] & (1 << b):
                    last[b] = i
            far = i
            for b in range(30):
                if last[b] != -1:
                    far = max(far, last[b])
            ans[i] = far - i + 1
        return ans

