var smallestSubarrays = function(nums) {
    const n = nums.length;
    const last = new Array(30).fill(-1);
    const ans = new Array(n).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        for (let b = 0; b < 30; b++) {
            if (nums[i] & (1 << b)) last[b] = i;
        }
        let far = i;
        for (let b = 0; b < 30; b++) {
            if (last[b] !== -1 && last[b] > far) far = last[b];
        }
        ans[i] = far - i + 1;
    }
    return ans;
};
